exercise.solution:
function lastItem<T>(arr: T[]): T | undefined {
  return arr[arr.length - 1];
}

interface Pair<T, U> {
  first: T;
  second: U;
}

const myPair: Pair<number, string> = {
  first: 42,
  second: "hello",
};

console.log(lastItem([10, 20, 30])); // 30
console.log(lastItem([]));           // undefined
console.log(myPair);                 // { first: 42, second: 'hello' }
